const fs = require('fs');
const path = require('path');

class ProblemsService {
  static async detail(problemId) {
    const problemsPath = path.join(__dirname, '../../data/problems.json');
    let problemsData;
    try {
      const raw = await fs.promises.readFile(problemsPath, 'utf-8');
      problemsData = JSON.parse(raw);
    } catch (e) {
      // If file read or parse fails, treat as no problems found
      return null;
    }

    const problem = problemsData.find(p => p.problemId === problemId);
    if (!problem) {
      return null;
    }

    // Aggregate component stats
    const componentStats = {
      languages: {},
      statusCounts: {},
      maxPoints: 0,
    };

    if (Array.isArray(problem.components)) {
      for (const comp of problem.components) {
        // Aggregate languages count
        if (comp.language) {
          componentStats.languages[comp.language] = (componentStats.languages[comp.language] || 0) + 1;
        }
        // Aggregate status counts
        if (comp.status) {
          componentStats.statusCounts[comp.status] = (componentStats.statusCounts[comp.status] || 0) + 1;
        }
        // Track max points
        if (typeof comp.points === 'number' && comp.points > componentStats.maxPoints) {
          componentStats.maxPoints = comp.points;
        }
      }
    }

    return {
      ...problem,
      componentStats,
    };
  }
}

module.exports = ProblemsService;
